  // <-- 此处到下面创建新 watcher 之间无锁，另有 fs:unwatch 调用也会操作 fsWatcher
  fsWatcher = fs.watch(watchPath, { recursive: true }, ...)
修复建议
使用 Promise 跟踪当前关闭操作，确保串行化：
  let closePromise: Promise<void> | null = null
  if (fsWatcher) closePromise = fsWatcher.close()
  if (closePromise) await closePromise
  fsWatcher = null

